            var name = type.Name;
            if (name.EndsWith(DataSuffix, StringComparison.Ordinal))
            {
                var originalName = name.Substring(0, name.Length - DataSuffix.Length);
                type.Update(
                    name: originalName,
                    relativeFilePath: Path.Combine("src", "Generated", $"{originalName}.cs"));
            }
        }
